import { emitEvent, mockTelegramEnv } from '@tma.js/sdk';
import { env } from '@shared/config/env';

/**
 * В обычном браузере нет `window.Telegram.WebApp`, без этого SDK не получает
 * launch params и TMA-API недоступны. Подмешиваем окружение до `initSDK()`.
 *
 * Импортируйте этот модуль самой первой строкой в `main.tsx` (только side-effect).
 */
const hasTelegramWebApp = (): boolean =>
  Boolean(
    typeof window !== 'undefined' &&
      (window as { Telegram?: { WebApp?: unknown } }).Telegram?.WebApp,
  );

/** true, если сработал mock — init() не должен await viewport/miniapp (в браузере host не отвечает). */
export let tmaBrowserMockActive = false;

if (env.tma.browserMock && !hasTelegramWebApp()) {
  tmaBrowserMockActive = true;
  // Схема @tma.js требует и tgWebAppThemeParams, и валидные RGB — иначе InvalidLaunchParamsError.
  mockTelegramEnv({
    launchParams: {
      tgWebAppPlatform: 'tdesktop',
      tgWebAppVersion: '8.0',
      tgWebAppThemeParams: {
        bg_color: '#18222d',
        text_color: '#f5f5f5',
        hint_color: '#708499',
        link_color: '#6ab2f2',
        button_color: '#5288c1',
        button_text_color: '#ffffff',
        accent_text_color: '#6ab2f2',
        section_bg_color: '#17212b',
        section_header_text_color: '#6ab2f2',
        subtitle_text_color: '#708499',
        section_separator_color: '#111a23',
        destructive_text_color: '#ec3942',
        secondary_bg_color: '#0f1923',
        header_bg_color: '#17212b',
        bottom_bar_bg_color: '#17212b',
      },
    },
    onEvent: (event, next) => {
      if (event.name === 'web_app_request_safe_area') {
        return emitEvent('safe_area_changed', { left: 0, top: 0, right: 0, bottom: 0 });
      }
      next();
    },
  });
}
