import { memo, useEffect, useCallback, useMemo, useState, useRef, type ReactNode } from 'react';
import useEmblaCarousel from 'embla-carousel-react';
import { WheelGesturesPlugin } from 'embla-carousel-wheel-gestures';
import cn from 'classnames';
import {
  installEmblaSliderProbe,
  isSliderDebugEnabled,
  logSliderDebugHint,
  useCardSliderRenderProbe,
} from '@shared/lib/dev/sliderDebug';
import styles from './CardSlider.module.scss';

export interface CardSliderItem {
  id: string;
}

export interface CardSliderProps<T extends CardSliderItem> {
  items: T[];
  selectedId?: string | null;
  /** Id элементов, помеченных как "настроенные" (имеют выбор, но не активны сейчас) */
  configuredIds?: string[];
  onSelect?: (id: string | null) => void;
  renderItem: (item: T, isSelected: boolean) => ReactNode;
  /** Визуальный класс для карточки (предопределённые: 'text' | 'image') */
  itemVariant?: 'text' | 'image';
  className?: string;
  /**
   * Только dev: подпись в [EmblaSliderProbe:…] / [CardSliderRender:…] — передавайте с родителя,
   * иначе оба слайдера в GenerateDock не различимы.
   */
  debugName?: string;
}

/** Пропсы только для карточек: без canScroll* — не ререндерим список при скролле. */
interface CardSliderListProps<T extends CardSliderItem> {
  items: T[];
  selectedId: string | null;
  configuredSet: Set<string> | null;
  itemVariant: 'text' | 'image';
  renderItem: (item: T, isSelected: boolean) => ReactNode;
  onItemSelect: (id: string) => void;
}

const CardSliderListComponent = <T extends CardSliderItem>({
  items,
  selectedId,
  configuredSet,
  itemVariant,
  renderItem,
  onItemSelect,
}: CardSliderListProps<T>) => (
  <div className={styles.emblaContainer}>
    {items.map((item) => {
      const isSelected = selectedId === item.id;
      const isConfigured = !isSelected && configuredSet?.has(item.id) === true;
      return (
        <div
          key={item.id}
          onClick={() => onItemSelect(item.id)}
          className={cn(
            styles.itemBase,
            itemVariant === 'text' && styles.itemText,
            itemVariant === 'image' && styles.itemImage,
            isSelected && styles.selected,
            isConfigured && styles.configured,
          )}
        >
          {renderItem(item, isSelected)}
        </div>
      );
    })}
  </div>
);

const CardSliderList = memo(CardSliderListComponent) as typeof CardSliderListComponent;

type ScrollEdges = { canPrev: boolean; canNext: boolean };

const edgesEqual = (a: ScrollEdges, b: ScrollEdges) => a.canPrev === b.canPrev && a.canNext === b.canNext;

/**
 * Горизонтальный слайдер на базе embla-carousel.
 * Controlled: selectedId приходит извне, onSelect вызывается только по клику.
 */
const CardSliderComponent = <T extends CardSliderItem>({
  items,
  selectedId = null,
  configuredIds,
  onSelect,
  renderItem,
  itemVariant = 'text',
  className,
  debugName = 'card-slider',
}: CardSliderProps<T>) => {
  const debugLabel = debugName;
  useCardSliderRenderProbe(debugLabel);

  const configuredSet = useMemo(
    () => (configuredIds ? new Set(configuredIds) : null),
    [configuredIds],
  );
  const wheelPlugins = useMemo(() => [WheelGesturesPlugin()], []);
  const [emblaRef, emblaApi] = useEmblaCarousel(
    { axis: 'x', dragFree: true, containScroll: 'trimSnaps' },
    wheelPlugins,
  );
  const [scrollEdges, setScrollEdges] = useState<ScrollEdges>({ canPrev: false, canNext: false });
  const lastEdges = useRef<ScrollEdges>({ canPrev: false, canNext: false });

  const updateScrollState = useCallback(() => {
    if (!emblaApi) return;
    const next: ScrollEdges = {
      canPrev: emblaApi.canScrollPrev(),
      canNext: emblaApi.canScrollNext(),
    };
    if (edgesEqual(next, lastEdges.current)) return;
    lastEdges.current = next;
    setScrollEdges(next);
  }, [emblaApi]);

  useEffect(() => {
    if (!isSliderDebugEnabled()) return;
    logSliderDebugHint();
  }, []);

  useEffect(() => {
    if (!emblaApi) return;
    updateScrollState();
    emblaApi.on('select', updateScrollState);
    emblaApi.on('reInit', updateScrollState);
    emblaApi.on('settle', updateScrollState);
    let offProbe: (() => void) | undefined;
    if (isSliderDebugEnabled()) {
      offProbe = installEmblaSliderProbe(emblaApi, debugLabel);
    }
    return () => {
      emblaApi.off('select', updateScrollState);
      emblaApi.off('reInit', updateScrollState);
      emblaApi.off('settle', updateScrollState);
      offProbe?.();
    };
  }, [emblaApi, updateScrollState, debugLabel]);

  const handleItemSelect = useCallback(
    (id: string) => {
      if (!onSelect) return;
      onSelect(selectedId === id ? null : id);
    },
    [selectedId, onSelect],
  );

  return (
    <div className={cn(styles.wrapper, className)}>
      {scrollEdges.canPrev && <div className={cn(styles.arrow, styles.arrowLeft)}>‹</div>}
      <div
        className={cn(styles.embla, {
          [styles.fadeLeft]: scrollEdges.canPrev,
          [styles.fadeRight]: scrollEdges.canNext,
        })}
        ref={emblaRef}
      >
        <CardSliderList
          items={items}
          selectedId={selectedId}
          configuredSet={configuredSet}
          itemVariant={itemVariant}
          renderItem={renderItem}
          onItemSelect={handleItemSelect}
        />
      </div>
      {scrollEdges.canNext && <div className={cn(styles.arrow, styles.arrowRight)}>›</div>}
    </div>
  );
};

export const CardSlider = memo(CardSliderComponent) as typeof CardSliderComponent;
