import { useRef } from 'react';
import type { EmblaCarouselType } from 'embla-carousel';
import { env } from '@shared/config/env';

/** Включение в dev: VITE_DEBUG_SLIDER=true, или в консоли: localStorage.setItem('__DEBUG_SLIDER__', '1') и F5. */
const LS_DEBUG_SLIDER = '__DEBUG_SLIDER__';

const readLocalEnabled = (): boolean => {
  try {
    return typeof localStorage !== 'undefined' && localStorage.getItem(LS_DEBUG_SLIDER) === '1';
  } catch {
    return false;
  }
};

/** Логи Embla + render probe для CardSlider. */
export const isSliderDebugEnabled = (): boolean =>
  import.meta.env.DEV && (env.debugSlider || readLocalEnabled());

/**
 * Считает события Embla за 1s и пишет в console.info (только при debug).
 * Смотрите, не растёт ли `scroll` в десятки/с — тогда слайдер дёргает React или mask/GPU.
 */
export const installEmblaSliderProbe = (
  embla: EmblaCarouselType,
  label: string,
): (() => void) => {
  if (!isSliderDebugEnabled()) {
    return () => undefined;
  }

  const tick = { scroll: 0, select: 0, settle: 0, reInit: 0, pointerUp: 0, pointerDown: 0 };
  const onScroll = () => {
    tick.scroll += 1;
  };
  const onSelect = () => {
    tick.select += 1;
  };
  const onSettle = () => {
    tick.settle += 1;
  };
  const onReInit = () => {
    tick.reInit += 1;
  };
  const onPointerUp = () => {
    tick.pointerUp += 1;
  };
  const onPointerDown = () => {
    tick.pointerDown += 1;
  };

  embla.on('scroll', onScroll);
  embla.on('select', onSelect);
  embla.on('settle', onSettle);
  embla.on('reInit', onReInit);
  embla.on('pointerUp', onPointerUp);
  embla.on('pointerDown', onPointerDown);

  const id = window.setInterval(() => {
    const n = tick.scroll + tick.select + tick.settle + tick.reInit;
    if (n > 0) {
      // eslint-disable-next-line no-console -- dev-only probe
      console.info(`[EmblaSliderProbe:${label}] events/sec`, { ...tick });
    }
    tick.scroll = 0;
    tick.select = 0;
    tick.settle = 0;
    tick.reInit = 0;
    tick.pointerUp = 0;
    tick.pointerDown = 0;
  }, 1000);

  return () => {
    window.clearInterval(id);
    embla.off('scroll', onScroll);
    embla.off('select', onSelect);
    embla.off('settle', onSettle);
    embla.off('reInit', onReInit);
    embla.off('pointerUp', onPointerUp);
    embla.off('pointerDown', onPointerDown);
  };
};

/**
 * Считает рендеры CardSlider. При большой частоте без скролла смотрите родителя (Redux) и пропы.
 */
export const useCardSliderRenderProbe = (name: string): void => {
  const n = useRef(0);
  n.current += 1;
  if (!isSliderDebugEnabled()) return;
  if (n.current === 1 || n.current % 25 === 0) {
    // eslint-disable-next-line no-console -- dev-only
    console.info(`[CardSliderRender] ${name} #${n.current}`);
  }
};

/** One-shot подсказка в консоль при первом маунте слайдера с дебагом. */
export const logSliderDebugHint = (): void => {
  if (!isSliderDebugEnabled()) return;
  const shown = '_sliderDebugHintShown';
  let first = true;
  try {
    if (typeof sessionStorage !== 'undefined' && sessionStorage.getItem(shown)) first = false;
    else if (typeof sessionStorage !== 'undefined') sessionStorage.setItem(shown, '1');
  } catch {
    /* session недоступен — показ подсказки не дедуплицируем */
  }
  if (!first) return;
  // eslint-disable-next-line no-console -- dev-only
  console.info(
    '[CardSlider] Debug: Profiler → Record → драг/скролл слайдера. Смотрите [EmblaSliderProbe] ' +
      '(события/s) и [CardSliderRender] (ререндеры). Выключить: localStorage.removeItem("__DEBUG_SLIDER__")',
  );
};
